import React from 'react';
import { Link } from 'react-router-dom';

function Services() {
  const serviceData = [
    { id: 1, title: "Web Development", icon: "fas fa-code", desc: "Modern, responsive websites built with React and Node.js.", color: "#0d6efd" },
    { id: 2, title: "UI/UX Design", icon: "fas fa-paint-brush", desc: "Creative and user-friendly interface designs.", color: "#dc3545" },
    { id: 3, title: "App Development", icon: "fas fa-mobile-alt", desc: "Custom Android and iOS applications.", color: "#198754" },
    { id: 4, title: "Assignment Support", icon: "fas fa-book-open", desc: "Expert help for academic projects and assignments.", color: "#ffc107" },
    { id: 5, title: "PPT Design", icon: "fas fa-file-powerpoint", desc: "Professional presentations for business and college.", color: "#0dcaf0" },
    { id: 6, title: "Report Writing", icon: "fas fa-file-alt", desc: "Detailed technical and business report writing.", color: "#6c757d" },
    { id: 7, title: "Digital Marketing", icon: "fas fa-bullhorn", desc: "Grow your online presence with social media ads.", color: "#343a40" },
    { id: 8, title: "Content Writing", icon: "fas fa-pen-nib", desc: "High-quality blog posts and creative writing.", color: "#0d6efd" },
    { id: 9, title: "SEO Optimization", icon: "fas fa-search-plus", desc: "Improve your website ranking on search engines.", color: "#0dcaf0" }
  ];

  return (
    <div className="services-page" style={{ backgroundColor: '#f8f9fa' }}>
      {/* 1. Attractive Header with Gradient */}
      <header className="py-5 text-white text-center shadow-lg" style={{ background: 'linear-gradient(135deg, #1e3c72 0%, #2a5298 100%)' }}>
        <div className="container py-4">
          <h1 className="fw-bold display-4 mb-3 animate__animated animate__fadeInDown">My Professional Services</h1>
          <p className="lead opacity-75 fs-5 mx-auto" style={{ maxWidth: '700px' }}>Tailored solutions designed for your digital success and academic excellence.</p>
          <div className="mx-auto mt-3 rounded-pill" style={{ width: '80px', height: '5px', backgroundColor: '#ffc107' }}></div>
        </div>
      </header>

      {/* 2. Services Grid with Modern Cards */}
      <section className="container py-5">
        <div className="row g-4">
          {serviceData.map((service) => (
            <div className="col-md-4" key={service.id}>
              <div className="card h-100 border-0 shadow-sm p-4 text-center service-card position-relative overflow-hidden">
                {/* Background Decoration */}
                <div className="card-bg-circle"></div>
                
                <div className="icon-box-premium mx-auto mb-4" style={{ color: service.color, backgroundColor: `${service.color}15` }}>
                  <i className={`${service.icon} fa-2x`}></i>
                </div>
                
                <h4 className="fw-bold mb-3" style={{ color: '#2c3e50' }}>{service.title}</h4>
                <p className="text-muted small mb-4">{service.desc}</p>
                
                <Link to="/register" className="btn mt-auto rounded-pill fw-bold shadow-sm action-btn" 
                      style={{ border: `2px solid ${service.color}`, color: service.color }}>
                  Get Started <i className="fas fa-chevron-right ms-1 small"></i>
                </Link>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* 3. How I Work Section with Process Flow */}
      <section className="py-5 bg-white border-top shadow-sm">
        <div className="container text-center">
          <h2 className="fw-bold mb-5">How I Work?</h2>
          <div className="row g-4 justify-content-center">
            {[
              { title: 'Consultation', desc: 'Discussing requirements to ensure perfect clarity.', icon: 'fa-comments' },
              { title: 'Strategy & Design', desc: 'Creating a personalized plan for your project.', icon: 'fa-lightbulb' },
              { title: 'Final Delivery', desc: 'Timely delivery with full professional support.', icon: 'fa-paper-plane' }
            ].map((step, index) => (
              <div className="col-md-4" key={index}>
                <div className="process-step-card p-4 h-100">
                  <div className="badge-step mb-3 mx-auto">{index + 1}</div>
                  <i className={`fas ${step.icon} text-primary mb-3 fa-2x d-block`}></i>
                  <h5 className="fw-bold">{step.title}</h5>
                  <p className="text-muted small px-3 mb-0">{step.desc}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Modern CSS Effects */}
      <style>{`
        .service-card { 
          transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275); 
          border-radius: 20px;
          z-index: 1;
        }
        .service-card:hover { 
          transform: translateY(-12px); 
          box-shadow: 0 20px 40px rgba(0,0,0,0.1) !important; 
        }
        .icon-box-premium {
          width: 70px;
          height: 70px;
          line-height: 75px;
          border-radius: 50%;
          display: flex;
          align-items: center;
          justify-content: center;
          transition: 0.3s;
        }
        .service-card:hover .icon-box-premium {
          transform: rotateY(360deg);
        }
        .action-btn {
          background: transparent;
          padding: 8px 20px;
          font-size: 0.9rem;
          transition: 0.3s;
        }
        .action-btn:hover {
          background-color: currentColor;
          color: #fff !important;
        }
        .card-bg-circle {
          position: absolute;
          top: -20px;
          right: -20px;
          width: 100px;
          height: 100px;
          background: rgba(0,0,0,0.02);
          border-radius: 50%;
          z-index: -1;
        }
        .badge-step {
          width: 40px;
          height: 40px;
          background: #0d6efd;
          color: white;
          border-radius: 50%;
          display: flex;
          align-items: center;
          justify-content: center;
          font-weight: bold;
          font-size: 1.1rem;
          box-shadow: 0 4px 10px rgba(13, 110, 253, 0.3);
        }
        .process-step-card {
          border-radius: 15px;
          transition: 0.3s;
        }
        .process-step-card:hover {
          background: #f8f9fa;
        }
      `}</style>
    </div>
  );
}

export default Services;
